SELECT
    cpi.*, task.ID_ AS task_id, task.NAME_ AS taskName, cu.nickname createByName
FROM cat_process_instance cpi
INNER JOIN cat_user cu on cpi.create_by = cu.id



        LEFT JOIN ACT_RU_TASK task ON cpi.process_instance_id = task.PROC_INST_ID_ AND task.ASSIGNEE_ = #{param.userId}
        WHERE cpi.deleted = '0'
          AND cpi.process_status = '0'
          AND cpi.create_by = #{param.userId}



        LEFT JOIN ACT_RU_TASK task ON cpi.process_instance_id = task.PROC_INST_ID_ AND task.ASSIGNEE_ = #{param.userId}
        WHERE cpi.deleted = '0'
          AND (
            cpi.create_by = #{param.userId}
            OR EXISTS (
                SELECT 1 FROM ACT_HI_TASKINST hti
                WHERE hti.PROC_INST_ID_ = cpi.process_instance_id
                  AND hti.ASSIGNEE_ = #{param.userId}
            )
          )



        INNER JOIN ACT_RU_TASK task ON cpi.process_instance_id = task.PROC_INST_ID_ AND task.ASSIGNEE_ = #{param.userId}
        WHERE cpi.deleted = '0'



        INNER JOIN ACT_RU_TASK task ON cpi.process_instance_id = task.PROC_INST_ID_
        INNER JOIN ACT_RU_IDENTITYLINK il ON il.TASK_ID_ = task.ID_
            AND il.TYPE_ = 'candidate'
            AND il.USER_ID_ = #{param.userId}
        WHERE cpi.deleted = '0'
          AND task.ASSIGNEE_ IS NULL



        WHERE 1 = 2
